import{_ as a,c as r,o as e,ae as t}from"./chunks/framework.BvcDoAct.js";const c=JSON.parse('{"title":"女团选秀是迈向更理想形态的一步","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART3/NoNoGirls.md","filePath":"zh-cn/Management2/PART3/NoNoGirls.md"}'),p={name:"zh-cn/Management2/PART3/NoNoGirls.md"};function n(s,o,l,i,h,N){return e(),r("div",null,[...o[0]||(o[0]=[t('<p>[2023-11]</p><h1 id="女团选秀是迈向更理想形态的一步" tabindex="-1">女团选秀是迈向更理想形态的一步 <a class="header-anchor" href="#女团选秀是迈向更理想形态的一步" aria-label="Permalink to &quot;女团选秀是迈向更理想形态的一步&quot;">​</a></h1><h3 id="「尽管我自己也曾受到各种结构性不平等的影响-却不禁自责-自己是否在无意间做着可能加剧性别差距的事。」" tabindex="-1">「尽管我自己也曾受到各种结构性不平等的影响，却不禁自责，自己是否在无意间做着可能加剧性别差距的事。」 <a class="header-anchor" href="#「尽管我自己也曾受到各种结构性不平等的影响-却不禁自责-自己是否在无意间做着可能加剧性别差距的事。」" aria-label="Permalink to &quot;「尽管我自己也曾受到各种结构性不平等的影响，却不禁自责，自己是否在无意间做着可能加剧性别差距的事。」&quot;">​</a></h3><p><strong>旨在发掘女子组合成员的选秀企划——&quot;GIRLS GROUP AUDITION PROJECT 2024《No No Girls》（以下简称《No No Girls》）目前正在推进中。报名已截止，选秀即将正式启动。本项目由BMSG邀请ちゃんみな担任制作人，并将在BMSG旗下设立全新的经纪管理组织，用于运营通过本次选秀诞生的女子组合。</strong></p><hr><p><strong>在《No No Girls》官方网站上，ちゃんみな写道：「我曾在无数场合被说‘No’。即便如此，我依然倾听自己灵魂的声音，继续唱歌跳舞。无论是有过与我相似经历的人，还是一直对自己说‘No’的人，如何看待这个‘No’由你决定。我相信其中一定包含着各种不同的视角与故事。希望大家让我听到你们的声音。」（原文照录）</strong></p><p><strong>我们首先询问了此次合作达成的原因。</strong></p><p>虽然与ちゃんみな一年只会见上几次，但几乎每一次见面，都会谈到类似本次企划的构想。她的厂牌「NO LABEL MUSIC」与我的「Be MySelf Group（=BMSG）」从名称就能看出，我们在信念、理念、对艺术的理解，以及对日本娱乐行业所存在的压力与问题意识方面，有着高度共通之处。拒绝过她的那个环境，与曾经拒绝过我的那个环境，虽然在细节上略有不同，但本质上其实非常接近。</p><p>我一直认为，ちゃんみな是与BMSG价值观最为接近的艺人之一。同时，她也对BMSG的理念与愿景深有共鸣，并始终给予支持。在《THE FIRST》时期，她甚至特地来到山梨的合宿现场。某种意义上说，与ちゃんみな合作，从创业之初就已经像是写进总体蓝图的计划。</p><p>我常常会想，如果像我这样的前辈，在我之上一代就已经存在，我或许会走得更轻松一些。或许如果我（36岁）与她（25岁）的年龄对调，先成立公司的人会是她，而我则可能像ちゃんみな那样活动。看着她，我能看到某种“自己未曾选择的人生”。因此，即使不需要花太多时间反复确认彼此想法，我们在核心价值层面大概也会得出相同的答案——这种安心感与期待感始终存在。</p><p>另一个原因是，当我看到她在横滨ARENA举办的演唱会「AREA OF DIAMOND」（2023年3月）时，我明确感受到她正处于艺术家阶段跃升的关键节点。此前我们共同接受采访时，她提到：“因为我18岁出道，所以至今仍保有强烈的新人心态。”我自己也是18岁出道，所以很能理解那种状态——心里还是个新人，但实际上已经活动了七年。她是时候迈入新的阶段了。甚至可以说，是那个阶段一直在等待她。如果要做，现在正是那个合适的时间，而且越早越好。</p><hr><h3 id="已具备打造女子组合的体制" tabindex="-1">已具备打造女子组合的体制 <a class="header-anchor" href="#已具备打造女子组合的体制" aria-label="Permalink to &quot;已具备打造女子组合的体制&quot;">​</a></h3><p><strong>目前BMSG旗下艺人均为男性。在这种情况下，公司内部也曾有人提出：“要不要考虑一下女性艺人的项目？”</strong></p><p>BMSG员工里女性比例相对较高，我们在招聘时也有意识地避免年龄与性别偏差。但在艺人层面，与培养团队讨论未来规划时，时常会出现“女生项目我们不是不推进吗？”的话题。只招募男性，本身多少显得有些与时代脱节。明明自己曾长期受到各种不平等结构的困扰，但从某种角度来看，我是否也在做着可能助长性别差距的事——对此我也有过深深的自责。而且，我想到明明有深刻认同BMSG理念、也具备能力的人，仅仅因为是女性而无法被接纳，这合理吗？我始终非常介意这点，但仅靠我自己的力量解决不了。正因如此，能够通过ちゃんみな，使BMSG向更理想的方向迈进一步，我由衷感激。</p><p>当然，我也曾怀疑BMSG是否真的具备举办女子组合选秀的组织能力与环境。幸运的是，自2023年春以来，新员工不断加入，公司组织结构显著强化。同时，水面下也有大量项目在推进，与既有规划之间需要统筹协调。综合时机来看，现在正是唯一合适的窗口。</p><p>当我向员工说明此次选秀时，出乎意料的是，许多员工展现出的热情甚至超过了我本人。我从整个环境中也能明显感受到时机已经成熟，这太重要了。当我所思考的方向，与身边人所思考的方向重合时，才有可能通过果断行动将势头放大。那样的话，“1”的意志会变成“2”、“4”、“8”……项目本身也会随之增强。</p><hr><p><strong>在《THE FIRST》时期，曾有人问到未来是否会制作女子组合，SKY-HI当时立即回答：“我应该不会做女团。”当时尚不清楚眼前男团的发展方向，因此这一回答可以理解。但如今他已在男子组合制作领域取得成绩，为何仍然避免亲自制作女子组合？</strong></p><p>我从一开始就没打算自己制作女子组合。过去我也曾说过“如果有五个ちゃんみな那样的人的话”或“如果由像ちゃんみな那样的人来做”的话就考虑做。从那时候起，我脑海里浮现的，与其说是“像ちゃんみな那样的人”，不如说一直只有“ちゃんみな”本人。至于这一点，我想，或许她自己是最清楚的吧（笑）。</p><p>我不做女团的原因很简单——我真的做不到。我并不是没有看过各种女团，但无论从经验还是审美偏好来说，我至今只真正切身体验过作为团体里的男性成员的艺术形式。女团的话，如果有人说“这个团很好，你看看”，我会觉得“确实很好”；若有人说“有点一般”，我也会觉得“好像是”。我对女团的感受力其实很有限。我的粉丝或许知道，我第一次真正喜欢上的女子组合成员，是LE SSERAFIM的金采源。我喜欢她的视觉呈现与表演力。即便她是solo，或者国籍是日本或美国，我大概也会喜欢（笑）。即便如此，我仍无法将“女团”视为自己的课题。而男子组合则不同——无论多喜欢，我都会从工作视角进行多层次思考。</p><hr><h3 id="在选秀中承担顾问的角色" tabindex="-1">在选秀中承担顾问的角色 <a class="header-anchor" href="#在选秀中承担顾问的角色" aria-label="Permalink to &quot;在选秀中承担顾问的角色&quot;">​</a></h3><p>虽然这可能多少也与女子组合有关，但我想稍微岔开一下话题。经常会听到“在舞台上把角色演到极致”这样的说法，但我对这种美学并不太有共鸣。这也和我自身的取向有关。无论是偶像还是艺人，那种以“完成角色”为核心的表演方式，大概今后也不会真正打动我。</p><p>为了履行被赋予的舞台角色而去彻底演绎，和为了定义自己、呈现自己而去打磨表演——这两者看似接近，其实有着本质区别。以ちゃんみな为例，在「AREA OF DIAMOND」中，《美人》舞台上卸妆的桥段曾引发巨大讨论。我能感受到，她在表演过程中一定精准计算了镜头位置等细节。她的冷静思考之上，是强烈的自我表达。这与一般所谓“完成角色”的含义，存在明显差异。</p><p>因此回到这次的话题——如果要由我承担押注的责任，做女团的人只能是ちゃんみな。在《No No Girls》的官方概念中，她提出“请向我展示你的声音与人生”。我对这种语言与感性深有共鸣。</p><p><strong>《No No Girls》的经纪管理将作为独立组织设立于BMSG旗下，但汇聚的仍是具备BMSG(Be MySelf)精神的人才。ちゃんみな和SKY-HI二位的角色分工如何？</strong></p><p>ちゃんみな将承担类似我在《THE FIRST》选秀时的角色，而我则负责后台体系搭建，同时充当她的顾问。 ちゃんみな无疑已经是出色的存在，但也可以说是一位人生经验稍微丰富一点的25岁女性。若以社会人视角类比，大概相当于入职第三年。她尚未经历过策划并推动大型项目、与外部公司系统协作的完整流程。当然，我相信她能够做到，我只做一个告诉她“这里没问题”或“这里可能得再考虑一下”的角色。我会对她说“没问题”，也会在现实层面确保事情真正“没问题”。但与此同时，我不能、也不适合将大量心力倾注在这个项目上。如果最终真的聚集了一群像ちゃんみな一样的人，也许我自己也能参与制作；但我更希望看到超越我想象的成果。综合而言，确实没有比ちゃんみな更合适的人选。</p><p>项目后续会如何发展，我也非常期待。真正启动后，我会以何种方式参与，尚未可知。只要这些女孩相信她，我相信她，她也相信我——只要这条信任链成立，我们自然会朝同一方向前进，所以我并不担心。</p>',29)])])}const G=a(p,[["render",n]]);export{c as __pageData,G as default};
